            detail = {'pred':cur_pred, 'answer':ref, 'correct':False}

            if cur_pred == ref:
                cnt += 1
                detail['correct'] = True

            details.append(detail)

        score = cnt / len(predictions) * 100
        return {'Accuracy': score, 'details': details}

