@beartype
class Evaluator(object):
    def __init__(self, eval_tag: str = "") -> None:
        self.eval_tag = eval_tag

    def __call__(
        self,
        trajectory: Trajectory,
        env: LLMAgentEnv,
        experiment_config: ExperimentConfig,
    ) -> float:
        raise NotImplementedError

    @staticmethod
    def get_last_action(trajectory: Trajectory) -> Action:
        try:
            # i'm confused but seems to work
            is_bearable(trajectory[-1].action, Action)
            last_action = trajectory[-1].action
        except Exception:
            raise ValueError(
                "The last element of trajectory should have an action, add a fake stop action if needed"
            )

        return last_action  # type: ignore[return-value]

    @staticmethod
    def get_last_state(trajectory: Trajectory) -> EnvOutput:
        try:
            is_bearable(trajectory[-1].env_output, EnvOutput)
            last_state = trajectory[-1].env_output
        except Exception:
            raise ValueError(
                "The last element of trajectory should contain a state, add a fake stop action if needed"
            )

        return last_state  # type: ignore[return-value]


def get_answer_from_action(action: Action) -> str:
    """This is kind of a hack to make BrowserAction and BashAction
    play nicely together"""
    if isinstance(action, BrowserAction):
        return action.data["answer"]
    elif isinstance(action, BashStopAction):
        return action.answer
    else:
        # for early stopping, sometimes we'll want an answer from a non-Stop action
        return ""


@beartype
class StringEvaluator(Evaluator):
    """Check whether the answer is correct with:
    exact match: the answer is exactly the same as the reference answer
    must include: each phrase in the reference answer must be included in the answer
    fuzzy match: the answer is similar to the reference answer, using LLM judge
    """

    def __call__(
        self,
        trajectory: Trajectory,
        env: LLMAgentEnv,
        experiment_config: ExperimentConfig,
    ) -> float:
        def clean_answer(answer: str) -> str:
            if answer.startswith("'") and answer.endswith("'"):
                answer = answer[1:-1]
            elif answer.startswith('"') and answer.endswith('"'):
                answer = answer[1:-1]
            return answer.lower()

        last_action = self.get_last_action(trajectory)
        pred = clean_answer(get_answer_from_action(last_action))

        score = 1.0
        reference_answers = experiment_config.eval.reference_answers
        assert reference_answers is not None, "uh oh, why is this None"
        for approach, value in reference_answers.items():
            if approach == "exact_match":
                assert isinstance(value, str)
                ref_answer = clean_answer(value)
                score = score * (pred == ref_answer)
            elif approach == "must_include":
                assert isinstance(value, list)
                for must_value in value:
                    must_value = clean_answer(must_value)
                    score = score * (must_value in pred)
            elif approach == "fuzzy_match":
                intent = experiment_config.goal
                assert isinstance(value, list)
                for reference in value:
                    fuzzy_score = llm_fuzzy_match(pred, reference, intent)
                    score = score * fuzzy_score
        return score


@beartype
class StringSoftEvaluator(Evaluator):
    """Use text generation metrics such as BLEU, ROUGE, etc. to evaluate the answer"""

    def __call__(
        self,
        trajectory: Trajectory,
        env: LLMAgentEnv,
        experiment_config: ExperimentConfig,
    ) -> float:
        last_action = self.get_last_action(trajectory)
        pred = get_answer_from_action(last_action)
        ref = experiment_config.eval.reference_answers
        # rouge
        m = evaluate.load("rouge")
        rouge = m.compute(predictions=[pred], references=[ref])
        return float(rouge["rouge1"])  # type: ignore [ian: i think they work]


class BrowserEvaluator(Evaluator):
    """Subclass specifically for evaluators that only work in the BrowserEnv"""


@beartype
class URLExactEvaluator(BrowserEvaluator):
    """Check whether the URL is exactly the same as of the reference URLs"""

    def __call__(
        self,
        trajectory: Trajectory,
        env: BrowserEnv,
        experiment_config: BrowserExperimentConfig,
    ) -> float:
        def clean_url(url: str) -> str:
            # NOTE: also dropping http:// and https://
            url = str(url)
            if url.endswith("/"):
                url = url[:-1]
            if url.startswith("http://"):
                url = url[7:]
            if url.startswith("https://"):
                url = url[8:]
            return url

        last_state = self.get_last_state(trajectory)
        assert isinstance(last_state, BrowserEnvOutput)
        last_page = last_state.info.page
        pred = clean_url(last_page.url)
        ref_urls = experiment_config.eval.reference_url.split(" |OR| ")
        ref_urls = [clean_url(url) for url in ref_urls]
        matching_rule = experiment_config.eval.url_note
        if matching_rule == "EXACT":
            if pred in ref_urls:
                return 1.0
            else:
                return 0.0
        elif matching_rule == "GOLD in PRED":
            if any([ref in pred for ref in ref_urls]):
                return 1.0
            else:
                return 0.0
        else:
            raise ValueError(f"Unknown matching rule: {matching_rule}")


@beartype
class HTMLContentExactEvaluator(BrowserEvaluator):
    """Check whether the contents appear in the page"""

    def __call__(
        self,
        trajectory: Trajectory,
        env: Union[BrowserEnv, BashBrowserEnv],
        experiment_config: Union[BrowserExperimentConfig, BashBrowserExperimentConfig],
    ) -> float:
        def clean(text: str) -> str:
            text = str(text)
            return text.strip().lower()

        targets = experiment_config.eval.program_html
        page = env.page

        score = 1.0
        for target in targets:
            target_url: str = target["url"]  # which url to check
            if target_url.startswith("func"):
                func = target_url.split("func:")[1]
                func = func.replace("__last_url__", page.url)
                target_url = eval(func)

            required_contents: str = target["required_contents"]  # what contents to check
            locator: str = target["locator"]  # js element locator

            # navigate to that url
            if target_url != "last":
                page.goto(target_url)
                time.sleep(3)  # TODO [shuyanzh]: fix this hard-coded sleep

            # empty, use the full page
            if not locator.strip():
                selected_element = page.content()
            # use JS to select the element
            elif locator.startswith("document."):
                try:
                    selected_element = page.evaluate(f"() => {locator}")
                    if not selected_element:
                        selected_element = ""
                    selected_element = str(selected_element)
                except Exception as e:
                    # the page is wrong, return empty
                    logger.error(f"Error in evaluating locator {locator}: {e}")
                    selected_element = ""
            # run program to call API
            elif locator.startswith("func:"):  # a helper function
                func = locator.split("func:")[1]
                func = func.replace("__page__", "page")
                selected_element = eval(func)
            else:
                raise ValueError(f"Unknown locator: {locator}")

            required_contents_or = [clean(x) for x in required_contents.split(" |OR| ")]
            selected_element = clean(selected_element)
            score *= any([content in selected_element for content in required_contents_or])

        return score


class EvaluatorComb(ABC):
    def __init__(self, evaluators: list[Evaluator]) -> None:
        self.evaluators = evaluators

    def __call__(
        self,
        trajectory: Trajectory,
        env: LLMAgentEnv,
        experiment_config: ExperimentConfig,
    ) -> float:
        score = 1.0
        for evaluator in self.evaluators:
            cur_score = evaluator(trajectory, env, experiment_config)
            # TODO: work out why it's done this way
            score *= cur_score
        return score


class BrowserEvaluatorComb(EvaluatorComb):
    def __init__(self, evaluators: list[BrowserEvaluator]) -> None:
        self.evaluators = evaluators


@beartype
def evaluator_router(experiment_config: ExperimentConfig) -> EvaluatorComb:
    if isinstance(experiment_config, BrowserExperimentConfig):
        assert isinstance(experiment_config, BrowserExperimentConfig)
        return browser_evaluator_router(experiment_config)
    elif isinstance(experiment_config, BashExperimentConfig):
        assert isinstance(experiment_config, BashExperimentConfig)
        return bash_evaluator_router(experiment_config)
    elif isinstance(experiment_config, BashBrowserExperimentConfig):
        assert isinstance(experiment_config, BashBrowserExperimentConfig)
        return bash_browser_evaluator_router(experiment_config)
    else:
        raise ValueError(f"Unknown experiment_config type {type(experiment_config)}")


@beartype
def browser_evaluator_router(
    experiment_config: BrowserExperimentConfig,
) -> EvaluatorComb:
    """Router to get the evaluator class"""

    # TODO: add 'eval' and maybe others to the experiment_config base class
    eval_types = experiment_config.eval.eval_types
    evaluators: list[Evaluator] = []
    for eval_type in eval_types:
        if eval_type == "string_match":
            evaluators.append(StringEvaluator())
        elif eval_type == "url_match":
            evaluators.append(URLExactEvaluator())
        elif eval_type == "program_html":
            evaluators.append(HTMLContentExactEvaluator())
        else:
            raise ValueError(f"eval_type {eval_type} is not supported")

    return EvaluatorComb(evaluators)


def bash_evaluator_router(
    experiment_config: BashExperimentConfig,
) -> EvaluatorComb:
    """Router to get the evaluator class"""
    # TODO: add 'eval' and maybe others to the experiment_config base class
    eval_types = experiment_config.eval.eval_types
    evaluators: list[Evaluator] = []
    for eval_type in eval_types:
        if eval_type == "string_match":
            evaluators.append(StringEvaluator())
        else:
            raise ValueError(f"eval_type {eval_type} is not supported")

    return EvaluatorComb(evaluators)


def bash_browser_evaluator_router(
    experiment_config: BashBrowserExperimentConfig,
) -> EvaluatorComb:
    """Router to get the evaluator class"""
    # TODO: add 'eval' and maybe others to the experiment_config base class
    eval_types = experiment_config.eval.eval_types
    evaluators: list[Evaluator] = []
    for eval_type in eval_types:
        if eval_type == "string_match":
            evaluators.append(StringEvaluator())
        elif eval_type == "url_match":
            evaluators.append(URLExactEvaluator())
        elif eval_type == "program_html":
            evaluators.append(HTMLContentExactEvaluator())
        else:
            raise ValueError(f"eval_type {eval_type} is not supported")

    return EvaluatorComb(evaluators)

import math
import os
from pathlib import Path
from typing import Optional

import evaluate
import torch
from accelerate import Accelerator
from accelerate.utils.dataclasses import DeepSpeedPlugin
from torch.distributed.fsdp import FullyShardedDataParallel as FSDP
from torch.nn.parallel import DistributedDataParallel as DDP
from torch.utils.data import DataLoader
from torchbenchmark.tasks import NLP
from torchbenchmark.util.e2emodel import E2EBenchmarkModel
from torchbenchmark.util.framework.transformers.text_classification.args import (
    parse_args,
    parse_torchbench_args,
)
from torchbenchmark.util.framework.transformers.text_classification.dataset import (
    prep_dataset,
    prep_labels,
    preprocess_dataset,
)
from transformers import (
    AdamW,
    AutoConfig,
    AutoModelForSequenceClassification,
    AutoTokenizer,
    DataCollatorWithPadding,
    default_data_collator,
    get_scheduler,
)

try:
    import torch._dynamo
except ImportError:
    pass

# setup environment variable
CURRENT_DIR = Path(os.path.dirname(os.path.realpath(__file__)))


class Model(E2EBenchmarkModel):
    task = NLP.LANGUAGE_MODELING
    DEFAULT_TRAIN_BSIZE: int = 32
    DEFAULT_EVAL_BSIZE: int = 1

    def __init__(self, test, batch_size=None, extra_args=[]):
        super().__init__(test=test, batch_size=batch_size, extra_args=extra_args)
        # TODO: currently only support 1 GPU device
        self.device = "cuda"
        self.device_num = 1
        # Parse the extra arguments
        self.tb_args = parse_torchbench_args(self.extra_args)
        torch.manual_seed(1337)
        torch.backends.cudnn.deterministic = False
        torch.backends.cudnn.benchmark = True

        # Parameters
        model_name = "bert-base-cased"
        max_seq_length = "128"
        learning_rate = "2e-5"
        num_train_epochs = "3"
        max_train_steps = "100"  # overrides num_train_epochs to run faster
        # this benchmark runs on a single GPU
        cuda_visible_devices = "0"
        output_dir = os.path.join(CURRENT_DIR, ".output")
        os.environ["CUDA_VISIBLE_DEVICES"] = cuda_visible_devices
        in_arg = [
            "--model_name_or_path",
            model_name,
            "--task_name",
            self.tb_args.task_name,
            "--max_length",
            max_seq_length,
            "--per_device_train_batch_size",
            str(self.batch_size),
            "--per_device_eval_batch_size",
            str(self.batch_size),
            "--learning_rate",
            learning_rate,
            "--num_train_epochs",
            num_train_epochs,
            "--max_train_steps",
            max_train_steps,
            "--output_dir",
            output_dir,
        ]
        hf_args = parse_args(in_arg)
        self.num_epochs = hf_args.num_train_epochs

        # ideally we don't modify the model code directly, but attaching deepspeed
        # must be done before self.prep initializes accelerator.
        if self.tb_args.distributed not in ["deepspeed", "ddp", "fsdp", "none"]:
            raise RuntimeError(
                f"Unsupported distributed scheme {self.tb_args.distributed} for model hf_t5"
            )
        if self.tb_args.distributed == "deepspeed":
            zero_opt_cfg = {
                "zero_optimization": {
                    "stage": 1,
                    "reduce_bucket_size": 2e8,
                    "overlap_comm": True,
                    "contiguous_gradients": False,
                }
            }
            hf_args.deepspeed_plugin = DeepSpeedPlugin()
            hf_args.deepspeed_plugin.deepspeed_config.update(zero_opt_cfg)
        hf_args.distributed = (
            self.tb_args.distributed
        )  # pass in distributed config to prep as a hf_arg

        # setup other members
        self.prep(hf_args)
        if test == "train":
            self.num_examples = len(self.train_dataloader) * self.batch_size
        elif test == "eval":
            self.num_examples = len(self.eval_dataloader) * self.batch_size

    def prep(self, hf_args):
        # Initialize the accelerator. We will let the accelerator handle device placement for us in this example.
        if hf_args.distributed == "deepspeed":
            # Note: self.tb_args.fp16 could be renamed to better clarify its meaning
            assert (
                self.tb_args.fp16 == "amp"
            ), "deepspeed is only supported with bf16/amp enabled"
            accelerator = Accelerator(
                deepspeed_plugin=hf_args.deepspeed_plugin, mixed_precision="bf16"
            )
        else:
            accelerator = Accelerator(
                mixed_precision="fp16" if self.tb_args.fp16 == "amp" else "no"
            )
        accelerator.wait_for_everyone()
        raw_datasets = prep_dataset(hf_args)
        num_labels, label_list, is_regression = prep_labels(hf_args, raw_datasets)
        # Load pretrained model and tokenizer
        #
        # In distributed training, the .from_pretrained methods guarantee that only one local process can concurrently
        # download model & vocab.
        config = AutoConfig.from_pretrained(
            hf_args.model_name_or_path,
            num_labels=num_labels,
            finetuning_task=hf_args.task_name,
        )
        tokenizer = AutoTokenizer.from_pretrained(
            hf_args.model_name_or_path, use_fast=not hf_args.use_slow_tokenizer
        )
        model = AutoModelForSequenceClassification.from_pretrained(
            hf_args.model_name_or_path,
            from_tf=bool(".ckpt" in hf_args.model_name_or_path),
            config=config,
        )
        train_dataset, eval_dataset, self.mnli_eval_dataset = preprocess_dataset(
            hf_args,
            config,
            model,
            tokenizer,
            raw_datasets,
            num_labels,
            label_list,
            is_regression,
            accelerator,
        )
        # DataLoaders creation:
        if hf_args.pad_to_max_length:
            # If padding was already done ot max length, we use the default data collator that will just convert everything
            # to tensors.
            self.data_collator = default_data_collator
        else:
            # Otherwise, `DataCollatorWithPadding` will apply dynamic padding for us (by padding to the maximum length of
            # the samples passed). When using mixed precision, we add `pad_to_multiple_of=8` to pad all tensors to multiple
            # of 8s, which will enable the use of Tensor Cores on NVIDIA hardware with compute capability >= 7.5 (Volta).
            self.data_collator = DataCollatorWithPadding(
                tokenizer, pad_to_multiple_of=(8 if accelerator.use_fp16 else None)
            )

        train_dataloader = DataLoader(
            train_dataset,
            shuffle=True,
            collate_fn=self.data_collator,
            batch_size=hf_args.per_device_train_batch_size,
        )
        eval_dataloader = DataLoader(
            eval_dataset,
            collate_fn=self.data_collator,
            batch_size=hf_args.per_device_eval_batch_size,
        )

        # transform model for DDP and FSDP
        if hf_args.distributed == "ddp":
            # prepare before wrap w/ DDP (or else error)
            model = accelerator.prepare(model)
            local_rank = int(os.getenv("LOCAL_RANK", -1))
            model = DDP(
                model,
                device_ids=[local_rank],
                # If buffer broadcast is necessary, specific optimizations might be
                # necessary to optimize performance. Disable it by default.
                broadcast_buffers=False,
                # Set gradient as bucket view to avoid unnecessary copies
                gradient_as_bucket_view=True,
                # TODO: tune bucket_cap_mb
                static_graph=True,
            )
        elif hf_args.distributed == "fsdp":
            # model needs to be prepared and wrapped w/ FSDP before optimizer is created, because FSDP flattens params
            model = accelerator.prepare(model)
            local_rank = int(os.getenv("LOCAL_RANK", -1))
            torch.cuda.set_device(local_rank)
            model = FSDP(model, device_id=torch.cuda.current_device())

        # Setup metrics
        # Get the metric function
        if hf_args.task_name is not None:
            self.metric = evaluate.load("glue", hf_args.task_name)
        else:
            self.metric = evaluate.load("accuracy")

        # Setup class members (model and the dataloaders will be updated in _prep_optimizer_and_scheduler() below)
        self.hf_args = hf_args
        self.is_regression = is_regression
        self.accelerator = accelerator
        self.model = model
        self.train_dataloader = train_dataloader
        self.eval_dataloader = eval_dataloader

        # Optimizer
        # Split weights in two groups, one with weight decay and the other not.
        no_decay = ["bias", "LayerNorm.weight"]
        optimizer_grouped_parameters = [
            {
                "params": [
                    p
                    for n, p in model.named_parameters()
                    if not any(nd in n for nd in no_decay)
                ],
                "weight_decay": hf_args.weight_decay,
            },
            {
                "params": [
                    p
                    for n, p in model.named_parameters()
                    if any(nd in n for nd in no_decay)
                ],
                "weight_decay": 0.0,
            },
        ]
        self.optimizer = AdamW(optimizer_grouped_parameters, lr=hf_args.learning_rate)
        self._update_everything_with_optimizer()

    def _update_everything_with_optimizer(self) -> None:
        # Prepare everything with our `accelerator` with deepspeed or non-distributed environment.
        if (
            self.hf_args.distributed == "deepspeed"
            or self.hf_args.distributed == "none"
        ):
            # deepspeed will error unless all components prepared at the same time
            self.model, self.train_dataloader, self.eval_dataloader, self.optimizer = (
                self.accelerator.prepare(
                    self.model,
                    self.train_dataloader,
                    self.eval_dataloader,
                    self.optimizer,
                )
            )
        else:
            # ddp and fsdp need model prepared before wrapping.
            self.train_dataloader, self.eval_dataloader, self.optimizer = (
                self.accelerator.prepare(
                    self.train_dataloader, self.eval_dataloader, self.optimizer
                )
            )

        # Note -> the training dataloader needs to be prepared before we grab his length below (cause its length will be
        # shorter in multiprocess)

        # Scheduler and math around the number of training steps.
        num_update_steps_per_epoch = math.ceil(
            len(self.train_dataloader) / self.hf_args.gradient_accumulation_steps
        )
        if self.hf_args.max_train_steps is None:
            self.hf_args.max_train_steps = (
                self.hf_args.num_train_epochs * num_update_steps_per_epoch
            )
        else:
            self.hf_args.num_train_epochs = math.ceil(
                self.hf_args.max_train_steps / num_update_steps_per_epoch
            )

        self.lr_scheduler = get_scheduler(
            name=self.hf_args.lr_scheduler_type,
            optimizer=self.optimizer,
            num_warmup_steps=self.hf_args.num_warmup_steps,
            num_training_steps=self.hf_args.max_train_steps,
        )

    def train(self) -> Optional[dict]:
        completed_steps = 0
        eval_metric = None
        for _epoch in range(self.hf_args.num_train_epochs):
            self.model.train()
            for step, batch in enumerate(self.train_dataloader):
                loss = self.run_forward(batch)
                loss = loss / self.hf_args.gradient_accumulation_steps
                self.run_backward(loss)
                if (
                    step % self.hf_args.gradient_accumulation_steps == 0
                    or step == len(self.train_dataloader) - 1
                ):
                    self.run_optimizer_step()
                    completed_steps += 1

                if completed_steps >= self.hf_args.max_train_steps:
                    break
            if self.tb_args.validate_in_train:
                self.model.eval()
                for step, batch in enumerate(self.eval_dataloader):
                    outputs = self.run_eval(batch)
                    predictions = (
                        outputs.logits.argmax(dim=-1)
                        if not self.is_regression
                        else outputs.logits.squeeze()
                    )
                    self.metric.add_batch(
                        predictions=self.accelerator.gather(predictions),
                        references=self.accelerator.gather(batch["labels"]),
                    )
                eval_metric = self.metric.compute()
        if self.tb_args.validate_in_train:
            if self.hf_args.task_name == "mnli":
                # Final evaluation on mismatched validation set
                eval_dataset = self.mnli_eval_dataset
                eval_dataloader = DataLoader(
                    eval_dataset,
                    collate_fn=self.data_collator,
                    batch_size=self.hf_args.per_device_eval_batch_size,
                )
                eval_dataloader = self.accelerator.prepare(eval_dataloader)

                self.model.eval()
                for step, batch in enumerate(eval_dataloader):
                    outputs = self.run_eval(batch)
                    predictions = outputs.logits.argmax(dim=-1)
                    self.metric.add_batch(
                        predictions=self.accelerator.gather(predictions),
                        references=self.accelerator.gather(batch["labels"]),
                    )

                eval_metric = self.metric.compute()
        # store accuracy results
        if self.hf_args.task_name == "cola" and self.tb_args.validate_in_train:
            self.accuracy = eval_metric["matthews_correlation"]
        return eval_metric

    def eval(self) -> Optional[dict]:
        self.model.eval()
        for _step, batch in enumerate(self.eval_dataloader):
            with torch.no_grad():
                outputs = self.run_eval(batch)
            predictions = (
                outputs.logits.argmax(dim=-1)
                if not self.is_regression
                else outputs.logits.squeeze()
            )
            self.metric.add_batch(
                predictions=self.accelerator.gather(predictions),
                references=self.accelerator.gather(batch["labels"]),
            )
        eval_metric = self.metric.compute()
        return eval_metric

    def get_optimizer(self):
        return self.optimizer

    def set_optimizer(self, optimizer) -> None:
        self.optimizer = optimizer
        self._update_everything_with_optimizer()

    def next_batch(self):
        return next(iter(self.train_dataloader))

    def run_forward(self, input):
        """
        compute model forward and return loss
        """
        if self.dynamo:
            backend = self.opt_args.torchdynamo
            return torch._dynamo.optimize(backend)(self._run_forward)(input)
        else:
            return self._run_forward(input)

    def _run_forward(self, input):
        return self.model(**input).loss

    def run_backward(self, loss):
        if self.dynamo:
            backend = self.opt_args.torchdynamo
            return torch._dynamo.optimize(backend)(self._run_backward)(loss)
        else:
            return self._run_backward(loss)

    def _run_backward(self, loss):
        self.accelerator.backward(loss)

    def get_optimizer(self):
        return self.optimizer

    def set_optimizer(self, optimizer) -> None:
        self.optimizer = optimizer

    def run_optimizer_step(self):
        if self.dynamo and not self.opt_args.dynamo_disable_optimizer_step:
            backend = self.opt_args.torchdynamo
            return torch._dynamo.optimize(backend)(self._run_optimizer_step)()
        else:
            return self._run_optimizer_step()

    def _run_optimizer_step(self):
        self.optimizer.step()
        self.lr_scheduler.step()
        self.optimizer.zero_grad()

    def run_eval(self, input):
        if self.dynamo:
            backend = self.opt_args.torchdynamo
            return torch._dynamo.optimize(backend)(self._run_eval)(input)
        else:
            return self._run_eval(input)

    def _run_eval(self, input):
        return self.model(**input)

import numbers
import re
from typing import Dict, List, Set

from datasets import load_dataset
import evaluate

from helm.benchmark.metrics.metric import MetricInterface, MetricResult, PerInstanceStats
from helm.benchmark.adaptation.scenario_state import ScenarioState
from helm.benchmark.metrics.metric_name import MetricName
from helm.benchmark.metrics.metric_service import MetricService
from helm.benchmark.metrics.statistic import Stat
from helm.common.hierarchical_logger import hwarn


class UnitxtMetric(MetricInterface):
    ID_PATTERN = re.compile("([a-z]+)([0-9]+)")

    def __init__(self, **kwargs):
        super().__init__()
        if len(kwargs) == 1 and "recipe" in kwargs:
            dataset_name = kwargs["recipe"]
        else:
            dataset_name = ",".join(f"{key}={value}" for key, value in kwargs.items())
        self.dataset = load_dataset("unitxt/data", dataset_name, trust_remote_code=True)

    def evaluate(
        self, scenario_state: ScenarioState, metric_service: MetricService, eval_cache_path: str, parallelism: int
    ) -> MetricResult:
        # Fetch references from dataset and make them parallel to predictions
        predictions: List[str] = []
        references: List = []
        for request_state in scenario_state.request_states:
            assert request_state.instance.id
            id_match = UnitxtMetric.ID_PATTERN.match(request_state.instance.id)
            assert id_match
            unitxt_split_name = id_match.group(1)
            row_index = int(id_match.group(2))
            references.append(self.dataset[unitxt_split_name][row_index])
            assert request_state.result
            assert len(request_state.result.completions) == 1
            predictions.append(request_state.result.completions[0].text)

        # Compute metrics
        evaluate_results: List[Dict] = evaluate.load("unitxt/metric").compute(
            predictions=predictions, references=references
        )

        # Extract instance metrics
        non_number_instance_metric_names: Set[str] = set()
        per_instance_stats: List[PerInstanceStats] = []
        for request_state, evaluate_result in zip(scenario_state.request_states, evaluate_results):
            instance = request_state.instance
            instance_stats: List[Stat] = []
            instance_results = evaluate_result["score"]["instance"]
            for metric_name, metric_score in instance_results.items():
                if metric_name == "score" or metric_name == "score_name":
                    continue
                stat = Stat(
                    MetricName(
                        name=metric_name,
                        split=instance.split,
                        sub_split=instance.sub_split,
                        perturbation=instance.perturbation,
                    )
                )
                if isinstance(metric_score, list):
                    for metric_score_element in metric_score:
                        if isinstance(metric_score_element, numbers.Number):
                            stat = stat.add(metric_score_element)
                        else:
                            non_number_instance_metric_names.add(metric_name)
                else:
                    if isinstance(metric_score, numbers.Number):
                        stat = stat.add(metric_score)
                    else:
                        non_number_instance_metric_names.add(metric_name)
                instance_stats.append(stat)
            assert instance.id
            per_instance_stats.append(
                PerInstanceStats(
                    instance_id=instance.id,
                    perturbation=instance.perturbation,
                    train_trial_index=request_state.train_trial_index,
                    stats=instance_stats,
                )
            )
        if non_number_instance_metric_names:
            hwarn(
                "Ignored Unitxt instance metrics because " f"they were not numbers: {non_number_instance_metric_names}"
            )

        # Extract global metrics
        aggregated_stats: List[Stat] = []
        if len(evaluate_results) > 0:
            global_results = evaluate_results[-1]["score"]["global"]
            for metric_name, metric_score in global_results.items():
                if metric_name == "score" or metric_name == "score_name":
                    continue
                stat = Stat(MetricName(name=metric_name))
                if isinstance(metric_score, list):
                    for metric_score_element in metric_score:
                        stat = stat.add(metric_score_element)
                else:
                    stat = stat.add(metric_score)
                aggregated_stats.append(stat)
        return MetricResult(aggregated_stats=aggregated_stats, per_instance_stats=per_instance_stats)
